+const store = mockStore({
+  user: {
+    appTheme: mockTheme.themeAppearance, // or any other relevant initial state
+  },
+});
+
+describe('ThemeProvider', () => {
+  it('should provide the correct theme to its children', () => {
+    const { getByTestId } = render(
