+					onPress={onClose}
+					containerStyle={styles.closeButton}
+					testID={NETWORK_EDUCATION_MODAL_CLOSE_BUTTON_ID}
+				>
+					{strings('network_information.got_it')}
+				</StyledButton>
+			</View>
+		</View>
+	);
